/**
 * Event Explorer Plugin
 * -----------------------
 * Plugin ini mendemonstrasikan bagaimana opencode events bekerja.
 * Setiap hook akan menampilkan log ke console sehingga Anda bisa
 * melihat urutan dan data yang mengalir di setiap event.
 */
export default (async () => {
  // --- State untuk custom tool events_status ---
  const eventCounts: Record<string, number> = {};
  const eventLog: Array<{ event: string; time: string; data?: unknown }> = [];

  function track(eventName: string, data?: unknown) {
    eventCounts[eventName] = (eventCounts[eventName] || 0) + 1;
    eventLog.push({ event: eventName, time: new Date().toISOString(), data });
  }

  function log(emoji: string, msg: string, data?: unknown) {
    const prefix = "[EVENT EXPLORER]";
    if (data) {
      console.log(`${prefix} ${emoji} ${msg}`, JSON.stringify(data, null, 2));
    } else {
      console.log(`${prefix} ${emoji} ${msg}`);
    }
  }

  return {
    // ==========================================
    // 1. CONFIG — dipanggil sekali saat init
    // ==========================================
    config: (cfg) => {
      track("config");
      log("🔧", "Config loaded!");
      log("📋", `Username: ${cfg.username ?? "(not set)"}`);
      log("🤖", `Model: ${cfg.model ?? "(not set)"}`);
      log("📦", `Plugins terdaftar: ${(cfg.plugin ?? []).length} entries`);
    },

    // ==========================================
    // 2. TOOL EXECUTION — sebelum & sesudah
    // ==========================================
    "tool.execute.before": async (input, output) => {
      track("tool.execute.before", { name: input.name });
      log("⚡", `BEFORE: "${input.name}"`, {
        args: output.args,
        toolCallId: input.toolCallId,
      });
    },

    "tool.execute.after": async (input, output) => {
      const status = output.error ? "❌ ERROR" : "✅ SUCCESS";
      track("tool.execute.after", { name: input.name, status: output.error ? "error" : "success" });
      log(status, `AFTER: "${input.name}"`, {
        duration: output.durationMs ? `${output.durationMs}ms` : "unknown",
        resultTruncated: output.result
          ? output.result.toString().substring(0, 200)
          : "(no result)",
        error: output.error ?? undefined,
      });
    },

    // ==========================================
    // 3. TOOL DEFINITION — saat tool didaftarkan
    // ==========================================
    "tool.definition": async (input, output) => {
      track("tool.definition", { name: input.name });
      log("🛠️", `Tool definition registered: "${input.name}"`);
    },

    // ==========================================
    // 4. CHAT — message & params ke LLM
    // ==========================================
    "chat.message": async (input, output) => {
      track("chat.message");
      const role = output?.role ?? "unknown";
      const contentPreview = output?.content
        ? output.content.toString().substring(0, 100)
        : "(empty)";
      log("💬", `Chat message [${role}]: "${contentPreview}..."`);
    },

    "chat.params": async (input, output) => {
      track("chat.params");
      log("🧠", "LLM Params disusun", {
        model: output?.model,
        maxTokens: output?.max_tokens,
        temperature: output?.temperature,
        stream: output?.stream,
      });
    },

    // ==========================================
    // 5. PERMISSION — saat user dimintai izin
    // ==========================================
    "permission.ask": async (input, output) => {
      track("permission.ask");
      log("🔐", `Permission asked: "${input?.action ?? "unknown action"}"`, {
        tool: input?.tool,
        args: input?.args,
      });
    },

    // ==========================================
    // 6. SHELL ENV — environment variables
    // ==========================================
    "shell.env": async (input, output) => {
      track("shell.env");
      const envKeys = Object.keys(output ?? {}).slice(0, 10);
      log("🌐", `Shell env dimuat (${Object.keys(output ?? {}).length} vars)`, {
        sample: envKeys,
      });
    },

    // ==========================================
    // 7. COMMAND EXECUTION
    // ==========================================
    "command.execute.before": async (input, output) => {
      track("command.execute.before");
      log("📟", `Custom command dijalankan: "${input?.name ?? "unknown"}"`);
    },

    // ==========================================
    // 8. CUSTOM TOOL — lihat statistik event
    // ==========================================
    tool: {
      events_status: {
        description:
          "Menampilkan ringkasan semua event yang telah ditangkap oleh Event Explorer plugin. Gunakan untuk melihat event apa saja yang sudah terjadi selama sesi ini.",
        parameters: {
          detail: {
            type: "string",
            enum: ["summary", "full"],
            description:
              '"summary" = hitungan per event (default), "full" = termasuk log detail',
          },
        },
        execute: async ({ detail }: { detail?: string }) => {
          const isFull = detail === "full";
          let output = `📊 EVENT EXPLORER — STATISTIK\n`;
          output += `══════════════════════════════\n`;
          output += `Total event tertangkap: ${eventLog.length}\n\n`;

          // Group by event type
          const sortedEvents = Object.entries(eventCounts).sort(
            ([, a], [, b]) => b - a
          );
          output += `📋 Per-event count:\n`;
          for (const [event, count] of sortedEvents) {
            output += `   ${event.padEnd(30)} ${count}x\n`;
          }

          if (isFull && eventLog.length > 0) {
            output += `\n📜 Detail log (${eventLog.length} entries):\n`;
            eventLog.forEach((entry, i) => {
              output += `   ${i + 1}. [${entry.time}] ${entry.event}\n`;
            });
          }

          output += `\n💡 Tip: Jalankan "events_status detail=full" untuk lihat semua log!`;
          return output;
        },
      },
    },
  };
}) satisfies Plugin;
"}

